import { withThemeByDataAttribute } from '@storybook/addon-themes';
const preview = {
    parameters: {
        controls: {
            matchers: {
                color: /(background|color)$/i,
                date: /Date$/i,
            },
        },
        backgrounds: { disable: true },
        layout: 'centered',
        options: {
            // Ordre de la sidebar : doit être inline (Storybook 8 ne suit pas les imports
            // dans cette config). Si on modifie, penser à synchroniser le preview React.
            storySort: {
                order: [
                    'À propos',
                    [
                        'Introduction',
                        'Décisions de design',
                        'Iconographie',
                        'Tokens',
                        ['Palette', 'Sémantique', 'Typographie', 'Spacing', 'Radii', 'Shadows'],
                        'Composants',
                        ['Button', 'Input', 'Textarea', 'Checkbox', 'Radio', 'Switch', 'Card', 'Alert', 'Dialog'],
                        'Différences React ↔ Angular',
                        'Décisions à prendre',
                    ],
                    'Composants',
                    ['Button', 'Input', 'Textarea', 'Checkbox', 'Radio', 'Switch', 'Card', 'Alert', 'Dialog'],
                ],
            },
        },
    },
    decorators: [
        withThemeByDataAttribute({
            themes: { light: 'light', dark: 'dark' },
            defaultTheme: 'light',
            attributeName: 'data-theme',
        }),
    ],
};
export default preview;
